/**
 * Tests for the knotgraft fabric server.
 *
 * Exercises the pure handlers (HTTP + FlowFrame encoders/decoders)
 * without binding sockets. The full multi-transport bootstrap is
 * tested manually via `scripts/run-knotgraft-fabric.ts`.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import {
  handleHttpIngest,
  processIngest,
  type KnotgraftFabricConfig,
} from '../knotgraft-fabric-server';
import type { TenantId } from '../prismatic-refraction-knotgraph';

const testTenant: TenantId = { hi: 0x1234_5678, lo: 0x9abc_def0 };

function baseConfig(overrides: Partial<KnotgraftFabricConfig> = {}): KnotgraftFabricConfig {
  return {
    defaultTenant: testTenant,
    laneCount: 8,
    emitSql: false,
    maxRequestBytes: 1024 * 1024,
    maxUdpPayloadBytes: 1400,
    ...overrides,
  };
}

function headers(entries: Record<string, string> = {}): Map<string, string> {
  const m = new Map<string, string>();
  for (const [k, v] of Object.entries(entries)) m.set(k.toLowerCase(), v);
  return m;
}

function makeBytes(n: number): Uint8Array {
  const out = new Uint8Array(n);
  for (let i = 0; i < n; i++) out[i] = (i * 37) & 0xff;
  return out;
}

// ─── processIngest (core transport-agnostic logic) ──────────────────

describe('knotgraft-fabric / processIngest', () => {
  it('stamps tenant into the response', () => {
    const result = processIngest(makeBytes(256), testTenant, 4, false);
    expect(result.tenantHi).toBe(testTenant.hi);
    expect(result.tenantLo).toBe(testTenant.lo);
    expect(result.laneCount).toBe(4);
    expect(result.totalBytes).toBe(256);
    expect(result.blocks).toBeLessThanOrEqual(4);
  });

  it('respects lane bound and preserves byte count', () => {
    for (const k of [1, 2, 4, 8, 16]) {
      const result = processIngest(makeBytes(1024), testTenant, k, false);
      expect(result.totalBytes).toBe(1024);
      for (const e of result.entries) {
        expect(e.regionId).toBeGreaterThanOrEqual(0);
        expect(e.regionId).toBeLessThan(k);
      }
    }
  });

  it('rejects invalid lane count', () => {
    expect(() => processIngest(makeBytes(8), testTenant, 0, false)).toThrow();
    expect(() => processIngest(makeBytes(8), testTenant, 17, false)).toThrow();
    expect(() => processIngest(makeBytes(8), testTenant, 1.5, false)).toThrow();
  });

  it('emits SQL when requested', () => {
    const result = processIngest(makeBytes(256), testTenant, 8, true);
    expect(result.sql).toBeDefined();
    expect(result.sql!.ddl).toContain('CREATE TABLE');
    expect(result.sql!.insertSql).toContain('INSERT INTO');
  });
});

// ─── HTTP handler (the normie projection) ────────────────────────────

describe('knotgraft-fabric / handleHttpIngest', () => {
  it('GET / returns a description', async () => {
    const res = await handleHttpIngest({
      config: baseConfig(),
      method: 'GET',
      path: '/',
      headers: headers(),
      body: new Uint8Array(0),
    });
    expect(res.status).toBe(200);
    const body = JSON.parse(new TextDecoder().decode(res.body));
    expect(body.endpoint).toBe('knotgraft-fabric');
    expect(body.transports.http).toBeGreaterThan(0);
    expect(body.transports.tcpFlow).toBeGreaterThan(0);
    expect(body.transports.udpFlow).toBeGreaterThan(0);
    expect(body.formal.crownTheorem).toBe('THM-WIRE-TO-STORAGE-IS-SOUND');
  });

  it('POST /ingest accepts raw bytes', async () => {
    const res = await handleHttpIngest({
      config: baseConfig(),
      method: 'POST',
      path: '/ingest',
      headers: headers(),
      body: makeBytes(512),
    });
    expect(res.status).toBe(200);
    const body = JSON.parse(new TextDecoder().decode(res.body));
    expect(body.totalBytes).toBe(512);
    expect(body.tenantHi).toBe(testTenant.hi);
  });

  it('POST / also accepts raw bytes (root alias)', async () => {
    const res = await handleHttpIngest({
      config: baseConfig(),
      method: 'POST',
      path: '/',
      headers: headers(),
      body: makeBytes(64),
    });
    expect(res.status).toBe(200);
  });

  it('401 when authToken configured and header missing', async () => {
    const res = await handleHttpIngest({
      config: baseConfig({ authToken: 'secret' }),
      method: 'POST',
      path: '/ingest',
      headers: headers(),
      body: makeBytes(8),
    });
    expect(res.status).toBe(401);
  });

  it('200 when authToken configured and header matches', async () => {
    const res = await handleHttpIngest({
      config: baseConfig({ authToken: 'secret' }),
      method: 'POST',
      path: '/ingest',
      headers: headers({ Authorization: 'Bearer secret' }),
      body: makeBytes(8),
    });
    expect(res.status).toBe(200);
  });

  it('413 payload_too_large above maxRequestBytes', async () => {
    const res = await handleHttpIngest({
      config: baseConfig({ maxRequestBytes: 100 }),
      method: 'POST',
      path: '/ingest',
      headers: headers(),
      body: makeBytes(200),
    });
    expect(res.status).toBe(413);
  });

  it('honors X-Knotgraft-Lane-Count header', async () => {
    const res = await handleHttpIngest({
      config: baseConfig({ laneCount: 16 }),
      method: 'POST',
      path: '/ingest',
      headers: headers({ 'X-Knotgraft-Lane-Count': '4' }),
      body: makeBytes(128),
    });
    expect(res.status).toBe(200);
    const body = JSON.parse(new TextDecoder().decode(res.body));
    expect(body.laneCount).toBe(4);
  });

  it('honors X-Knotgraft-Emit-Sql header', async () => {
    const res = await handleHttpIngest({
      config: baseConfig(),
      method: 'POST',
      path: '/ingest',
      headers: headers({ 'X-Knotgraft-Emit-Sql': 'true' }),
      body: makeBytes(64),
    });
    expect(res.status).toBe(200);
    const body = JSON.parse(new TextDecoder().decode(res.body));
    expect(body.sql).toBeDefined();
  });

  it('404 for unknown paths', async () => {
    const res = await handleHttpIngest({
      config: baseConfig(),
      method: 'POST',
      path: '/wrong',
      headers: headers(),
      body: new Uint8Array(0),
    });
    expect(res.status).toBe(404);
  });
});

// Transport-level FlowFrame wire tests now live in `@a0n/aeon/fabric`'s
// own test suite. Knotgraft-specific tests above cover the handler
// policy (auth, size cap, tenant stamp, soundness witness).
